import { Card } from "@lifesg/react-design-system/card";
import styled from "styled-components";

export const StyledCard = styled(Card)`
    border-radius: 4px;
    padding: 1rem 2rem;
    max-width: 30rem;
    /* Other CSS properties... */
`;

import { Color } from "@lifesg/react-design-system/color";
import styled, { css } from "styled-components";

const Container = styled.div`
    background: ${Color.Primary};

    // If you extract props, remember to wrap nested interpolations with the css helper
    ${(props) => {
        return css`
            color: ${Color.Secondary};
        `;
    }}

    // Otherwise, you have to pass the props down manually (not recommended)
	${(props) => {
        return `
			color: ${Color.Secondary(props)};
		`;
    }}
`;

import { Color } from "@lifesg/react-design-system/color";
import { BaseTheme } from "@lifesg/react-design-system/theme";

const PrimaryColor = Color.Primary({ theme: BaseTheme });

// If you are using Styled Components

export const CustomErrorDisplay = styled(ErrorDisplay)`
    [data-id="error-display-image"] {
        /* Your styles here */
    }
`;

import { DisclaimerLinks, Footer } from "@lifesg/react-design-system/footer";

const disclaimerLinks: DisclaimerLinks = {
    reportVulnerability: {
        href: "https://tech.gov.sg/report_vulnerability",
        target: "_blank",
        rel: "noopener",
        external: true,
    },
};

return (
	<Footer disclaimerLinks={disclaimerLinks} />;
);

import { Layout } from "@lifesg/react-design-system/layout";
import styled from "styled-components";

// Method 1: Using the data-id property
export const ModifiedContent = styled(Layout.Content)`
    /* Modifying styles here will modify the Section component */

    [data-id="container"] {
        /* Modifying styles here will modify the Container component */
    }
`;

// Method 2: Using the component itself
export const ModifiedContent2 = styled(Layout.Content)`
    /* Modifying styles here will modify the Section component */

    ${Layout.Container} {
        /* Modifying styles here will modify the Container component */
    }
`;

import { withNotificationBanner } from "@lifesg/react-design-system/notification-banner";

const HOCElement = withNotificationBanner([
    {
        type: "text",
        content: "This is rendered using the HOC, and it contains a&nbsp;",
    },
    {
        type: "link",
        content: "hyperlink",
        otherAttributes: {
            href: "https://www.google.com",
            external: true,
            target: "_blank",
        },
    },
    {
        type: "text",
        content:
            "&nbsp;and text with styles like <strong>bold</strong> and <em>italics</em>.",
    },
]);

const MainRender = () => {
    return (
        <StyledContainer>
            <HOCElement dismissable={false} />
            other content renders...
        </StyledContainer>
    );
};

import { Text } from "@lifesg/react-design-system/text";

const Trigger = () => (
    <CustomDiv>
        <Text.Body>Hover me</Text.Body>
    </CustomDiv>
);

const PopoverHOC = withPopover(Trigger, {
    content: "This is the popover content",
    trigger: "hover",
});

export const CustomOrderedList = styled(TextList.Ol)`
    margin-left: 2rem;

    li {
        margin-left: 1rem;
    }

    li:before {
        content: counters(list, ".") ".";
        left: -3rem;
    }

    ${MediaQuery.MaxWidth.mobileL} {
        li {
            margin-left: 1rem;
        }
        li:before {
            left: -3rem;
        }
    }
`;

import { Button, ButtonProps } from "@lifesg/react-design-system/button";

const TriggerComponent = (props: ButtonProps) => (
    <Button.Default {...props}>Click on me</Button.Default>
);

const WrappedComponent = withTooltip(TriggerComponent, {
    content: "This is my tooltip",
});
